import{_ as a,o as n,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"风电产业链","description":"","frontmatter":{"updated":"2026-06-23T00:00:00.000Z","visibility":"public"},"headers":[],"relativePath":"电力新能源/风电/产业链.md","filePath":"电力新能源/风电/产业链.md","lastUpdated":1781535932000}'),r={name:"电力新能源/风电/产业链.md"};function e(l,t,p,o,i,h){return n(),s("div",null,[...t[0]||(t[0]=[d(`<h1 id="风电产业链" tabindex="-1">风电产业链 <a class="header-anchor" href="#风电产业链" aria-label="Permalink to &quot;风电产业链&quot;">​</a></h1><p><strong>成熟度：</strong> 主产业链成熟，浮式/深远海/运维数字化早期 <strong>PE/VC 重心：</strong> 浮式风电、智慧运维、叶片回收、风电数字化 <strong>数据来源：</strong> China Energy MCP（国家能源局/中电联）、Prospector Energy MCP（美国并网队列 + NREL ATB） <strong>数据获取：</strong> 2026-06-15</p><hr><h2 id="一、产业链全景" tabindex="-1">一、产业链全景 <a class="header-anchor" href="#一、产业链全景" aria-label="Permalink to &quot;一、产业链全景&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>上游（零部件）               中游（整机制造）             下游（风场运营）</span></span>
<span class="line"><span>────────────────            ──────────────            ──────────────</span></span>
<span class="line"><span>叶片                             整机                       风场开发</span></span>
<span class="line"><span>  ├── 玻纤/碳纤复合材料               ├── 陆上风机                   ├── 选址+环评+核准</span></span>
<span class="line"><span>  └── 叶片设计/认证                   ├── 海上风机                   └── 融资+建设</span></span>
<span class="line"><span>                                    └── 漂浮式风机（原型）</span></span>
<span class="line"><span>齿轮箱                                                         ──────────────</span></span>
<span class="line"><span>  ├── 南高齿/重齿/威能极            ↓                          运维服务</span></span>
<span class="line"><span>  └── 中速传动（新技术方向）                                   ├── 定期维护</span></span>
<span class="line"><span>                                                             ├── 状态监测(CMS)</span></span>
<span class="line"><span>轴承                           风场EPC                        ├── 故障诊断</span></span>
<span class="line"><span>  ├── 主轴轴承（洛轴/瓦轴）          ├── 海上施工（船机）              └── 大修+技改</span></span>
<span class="line"><span>  ├── 偏航变桨轴承                  └── 海缆铺设</span></span>
<span class="line"><span>  └── 齿轮箱轴承（国产化中）                                   ──────────────</span></span>
<span class="line"><span>                                                            数字化/软件</span></span>
<span class="line"><span>发电机                                                       ├── SCADA</span></span>
<span class="line"><span>  ├── 双馈异步                     风场运营方                    ├── 风功率预测</span></span>
<span class="line"><span>  └── 永磁同步                      ├── 五大六小发电集团             └── 智慧运维平台</span></span>
<span class="line"><span>                                   ├── 地方能源集团</span></span>
<span class="line"><span>变流器                             └── 独立运营商                  退役回收</span></span>
<span class="line"><span>  ├── 禾望/阳光电源                                                   └── 叶片回收/材料循环</span></span>
<span class="line"><span>  └── 中车时代电气</span></span></code></pre></div><hr><h2 id="二、各环节分析" tabindex="-1">二、各环节分析 <a class="header-anchor" href="#二、各环节分析" aria-label="Permalink to &quot;二、各环节分析&quot;">​</a></h2><h3 id="_2-1-叶片" tabindex="-1">2.1 叶片 <a class="header-anchor" href="#_2-1-叶片" aria-label="Permalink to &quot;2.1 叶片&quot;">​</a></h3><ul><li><strong>材料：</strong> 玻纤（主流）→ 碳纤（大叶片趋势，&gt;100m）</li><li><strong>技术趋势：</strong> 可回收树脂（热塑性）、分段叶片、智能叶片（传感器内嵌）</li><li><strong>国产化程度：</strong> 中材/时代新材/中复连众 主导，CR3 &gt;60%</li><li><strong>一级机会：</strong> ⭐ 叶片回收技术、可回收树脂、叶片智能化</li></ul><h3 id="_2-2-齿轮箱-传动链" tabindex="-1">2.2 齿轮箱/传动链 <a class="header-anchor" href="#_2-2-齿轮箱-传动链" aria-label="Permalink to &quot;2.2 齿轮箱/传动链&quot;">​</a></h3><ul><li>南高齿全球龙头，市占率 &gt;25%</li><li>中速传动（半直驱）方案渗透率提升（减少齿轮箱级数）</li><li><strong>一级机会：</strong> 中速传动方案创新、轴承国产化（齿轮箱轴承）</li></ul><h3 id="_2-3-整机制造" tabindex="-1">2.3 整机制造 <a class="header-anchor" href="#_2-3-整机制造" aria-label="Permalink to &quot;2.3 整机制造&quot;">​</a></h3><p><strong>格局：</strong></p><table tabindex="0"><thead><tr><th>排名</th><th>2025中国陆上</th><th>2025中国海上</th></tr></thead><tbody><tr><td>1</td><td>金风科技</td><td>电气风电</td></tr><tr><td>2</td><td>远景能源</td><td>明阳智能</td></tr><tr><td>3</td><td>运达股份</td><td>金风科技</td></tr><tr><td>4</td><td>明阳智能</td><td>远景能源</td></tr><tr><td>5</td><td>三一重能</td><td>中国海装</td></tr></tbody></table><p><strong>趋势：</strong></p><ul><li>大型化加速：陆上 6-10MW，海上 15-20MW</li><li>价格战持续（陆上风机价格降至 1000-1500元/kW）</li><li>整机利润薄，靠运维+服务获取后市场收益</li></ul><p><strong>一级机会：</strong> ⚠️ 整机制造投资机会有限（龙头已上市或不融资）</p><h3 id="_2-4-海上风电" tabindex="-1">2.4 海上风电 <a class="header-anchor" href="#_2-4-海上风电" aria-label="Permalink to &quot;2.4 海上风电&quot;">​</a></h3><p><strong>当前状态：</strong></p><ul><li>2025年中国海上风电累计装机 ~40GW，全球第一</li><li>国补退出后省补接力，广东/浙江/山东/江苏/福建力度不一</li><li>2025年起海风进入市场化竞争阶段</li></ul><p><strong>技术方向：</strong></p><table tabindex="0"><thead><tr><th>技术</th><th>水深</th><th>成熟度</th><th>机会</th></tr></thead><tbody><tr><td>单桩固定式</td><td>&lt;30m</td><td>成熟</td><td>❌</td></tr><tr><td>导管架固定式</td><td>30-60m</td><td>成熟</td><td>❌</td></tr><tr><td>半潜式浮式</td><td>&gt;60m</td><td>示范/预商业</td><td>✅</td></tr><tr><td>张力腿浮式</td><td>&gt;60m</td><td>研发</td><td>✅</td></tr></tbody></table><p><strong>一级机会：</strong> ⭐⭐ 浮式风电平台设计/系泊系统/动态海缆</p><hr><h2 id="三、中国市场装机与关键指标" tabindex="-1">三、中国市场装机与关键指标 <a class="header-anchor" href="#三、中国市场装机与关键指标" aria-label="Permalink to &quot;三、中国市场装机与关键指标&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>数据</th></tr></thead><tbody><tr><td>风电累计装机（中国）</td><td><strong>5.2亿千瓦</strong>（520 GW）</td></tr><tr><td>2025年新增</td><td>约8,000万千瓦</td></tr><tr><td>风电年发电量</td><td>10,531亿千瓦时</td></tr><tr><td>风电利用率</td><td>96.0%</td></tr><tr><td>陆上风电IRR</td><td>6-9%（资本金）</td></tr><tr><td>海上风电IRR</td><td>4-6%（资本金）</td></tr></tbody></table><blockquote><p>利用率保持96%+健康水平，但区域分化明显（云南97.5% vs 青海89.5%）</p></blockquote><p><strong>中国TOP5风电省份：</strong></p><table tabindex="0"><thead><tr><th>排名</th><th>省份</th><th>风电装机(万kW)</th><th>利用率</th><th>利用小时</th><th>特点</th></tr></thead><tbody><tr><td>1</td><td><strong>内蒙古</strong></td><td>8,200</td><td>93.5%</td><td>2,500-3,200h</td><td>风资源全国最优，蒙西电价市场化</td></tr><tr><td>2</td><td><strong>新疆</strong></td><td>4,500</td><td>91.8%</td><td>2,200-3,000h</td><td>广袤风场，利用率偏低</td></tr><tr><td>3</td><td><strong>河北</strong></td><td>3,800</td><td>94.2%</td><td>2,000-2,600h</td><td>靠近负荷中心（京津冀）</td></tr><tr><td>4</td><td><strong>甘肃</strong></td><td>3,200</td><td>92.5%</td><td>2,000-2,800h</td><td>现货市场正式运行</td></tr><tr><td>5</td><td><strong>江苏</strong></td><td>3,200</td><td>96.5%</td><td>—</td><td>海上风电大省</td></tr></tbody></table><blockquote><p>🔗 数据来源：<code>china-energy_get_national_stats</code>, <code>china-energy_get_province_stats</code></p></blockquote><p><strong>美国市场参考（Prospector Energy 并网队列）：</strong></p><table tabindex="0"><thead><tr><th>指标</th><th>数据</th></tr></thead><tbody><tr><td>纯风电项目数</td><td>6,526</td></tr><tr><td>总排队容量</td><td>1,245.9 GW</td></tr><tr><td>海上风电项目</td><td>121项，47.4 GW</td></tr><tr><td>Wind+Storage混合</td><td>80项，39.4 GW</td></tr><tr><td>IRA PTC/ITC</td><td>风电可选PTC（$28.35/MWh, indexed）或ITC 30%</td></tr><tr><td>能源社区风电项目</td><td>大量在册项目符合能源社区附加</td></tr></tbody></table><blockquote><p>美国风电队列以陆上为主，海风仍早期（121项/47GW，远低于欧洲）</p></blockquote><p><strong>中美风电对比（一级视角）：</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>中国</th><th>美国</th></tr></thead><tbody><tr><td>装机</td><td>520 GW（全球第一）</td><td>~150 GW</td></tr><tr><td>年新增</td><td>~80 GW</td><td>~15-20 GW</td></tr><tr><td>陆上风机均价</td><td>1,000-1,500元/kW</td><td>~$900-1,200/kW</td></tr><tr><td>标杆IRR</td><td>6-9%</td><td>PTC后7-12%</td></tr><tr><td>PE/VC机会</td><td>浮式风电/运维/叶片回收</td><td>项目融资/运维平台/ITC交易</td></tr></tbody></table><blockquote><p>🔗 数据来源：<code>prospector-energy_get_queue_stats</code></p></blockquote><hr><h2 id="四、产业链利润分布" tabindex="-1">四、产业链利润分布 <a class="header-anchor" href="#四、产业链利润分布" aria-label="Permalink to &quot;四、产业链利润分布&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>高利润区:</span></span>
<span class="line"><span>  - 核心零部件（主轴承/齿轮箱，壁垒高）</span></span>
<span class="line"><span>  - 海上风电施工船（资源稀缺）</span></span>
<span class="line"><span>  - 后市场服务/运维（高毛利率 30-50%）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>中利润区:</span></span>
<span class="line"><span>  - 叶片（大型化+碳纤带来技术溢价）</span></span>
<span class="line"><span>  - 海上风机（受省补支撑）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>低利润区:</span></span>
<span class="line"><span>  - 陆上整机（价格战，毛利率&lt;10%）</span></span>
<span class="line"><span>  - 常规运维（竞争激烈）</span></span></code></pre></div><hr><h2 id="五、关键趋势" tabindex="-1">五、关键趋势 <a class="header-anchor" href="#五、关键趋势" aria-label="Permalink to &quot;五、关键趋势&quot;">​</a></h2><ol><li><strong>浮式风电商业化前夜</strong> — 全球示范项目&gt;30个，降本路径清晰</li><li><strong>风电出海</strong> — 中国整机/零部件出口+海外建厂（中东/中亚/南美）</li><li><strong>风电+氢能</strong> — 海上风电制氢（Power-to-X）</li><li><strong>数字化运维</strong> — 状态监测CMS+AI预测+无人机巡检</li><li><strong>叶片回收循环经济</strong> — 2028-2030第一波退役高峰</li></ol>`,42)])])}const b=a(r,[["render",e]]);export{g as __pageData,b as default};
